#include "hirct/Analysis/IRAnalysis.h"

#include <cctype>
#include <cerrno>
#include <cstring>
#include <fstream>
#include <iostream>
#include <sys/stat.h>

namespace hirct {

static constexpr const char *AUTO_GENERATED_HEADER_MD =
    "> AUTO-GENERATED by hirct-gen \xe2\x80\x94 DO NOT EDIT\n";

static std::string to_lower(const std::string &s) {
  std::string r;
  r.reserve(s.size());
  for (char c : s)
    r += static_cast<char>(tolower(static_cast<unsigned char>(c)));
  return r;
}

static bool ends_with(const std::string &s, const std::string &suffix) {
  return s.size() >= suffix.size() &&
         s.compare(s.size() - suffix.size(), suffix.size(), suffix) == 0;
}

static bool starts_with(const std::string &s, const std::string &prefix) {
  return s.size() >= prefix.size() && s.compare(0, prefix.size(), prefix) == 0;
}

GenDoc::GenDoc(circt::hw::HWModuleOp hw_module) : hw_module_(hw_module) {}

std::string GenDoc::port_description(const std::string &name) {
  if (hirct::is_clock_port(name))
    return "Clock signal";
  if (hirct::is_reset_port(name))
    return hirct::is_active_low_reset(name) ? "Active-low reset"
                                            : "Active-high reset";
  return "";
}

bool GenDoc::emit(const std::string &output_dir) {
  std::string name = hw_module_.getSymName().str();
  bool has_instances = false;
  bool has_registers = false;
  int comb_count = 0;
  int instance_count = 0;
  std::vector<std::pair<std::string, std::string>> instances;

  auto ports = hirct::get_ports(hw_module_);
  auto input_ports = hirct::get_input_ports(hw_module_);
  auto output_ports = hirct::get_output_ports(hw_module_);
  auto reg_views = hirct::collect_registers(hw_module_);
  has_registers = !reg_views.empty();
  hw_module_.walk([&](circt::hw::InstanceOp inst) {
    has_instances = true;
    std::string inst_name = inst.getInstanceName().str();
    std::string mod_type = inst.getModuleNameAttr().getValue().str();
    instances.emplace_back(inst_name, mod_type);
  });
  hw_module_.walk([&](mlir::Operation *op) {
    llvm::StringRef opName = op->getName().getStringRef();
    if (opName.starts_with("comb."))
      ++comb_count;
    if (mlir::isa<circt::hw::InstanceOp>(op))
      ++instance_count;
  });

  std::string doc_dir = output_dir + "/doc";
  if (mkdir(doc_dir.c_str(), 0755) != 0 && errno != EEXIST) {
    std::cerr << "GenDoc: cannot create directory: " << doc_dir << ": "
              << strerror(errno) << "\n";
    return false;
  }

  std::string path = doc_dir + "/" + name + ".md";

  std::ofstream ofs(path);
  if (!ofs) {
    std::cerr << "GenDoc: cannot open " << path << "\n";
    return false;
  }

  ofs << "# " << name << " Hardware Documentation\n\n";
  ofs << AUTO_GENERATED_HEADER_MD << "\n";

  bool has_clock = false;
  bool has_reset = false;
  for (const auto &p : ports) {
    if (!has_clock && hirct::is_clock_port(p.name))
      has_clock = true;
    if (!has_reset && hirct::is_reset_port(p.name))
      has_reset = true;
  }

  emit_hardware_spec(ofs, ports, reg_views, comb_count, instance_count);
  emit_programmers_guide(ofs, has_clock, has_reset, name, ports, input_ports,
                         output_ports, has_registers);
  if (has_instances)
    emit_module_hierarchy(ofs, name, instances);

  return true;
}

void GenDoc::emit_hardware_spec(
    std::ofstream &ofs, const std::vector<PortView> &ports,
    const std::vector<RegisterView> &registers, int comb_count,
    int instance_count) {
  ofs << "## Hardware Spec\n\n";
  emit_port_map(ofs, ports);
  emit_internal_signals(ofs, registers, comb_count, instance_count);
  if (!registers.empty())
    emit_register_summary(ofs, registers);
}

void GenDoc::emit_port_map(std::ofstream &ofs,
                           const std::vector<PortView> &ports) {
  ofs << "### Port Map\n\n";
  ofs << "| Name | Direction | Width | Description |\n";
  ofs << "|------|-----------|-------|-------------|\n";
  for (const auto &p : ports) {
    std::string desc = port_description(p.name);
    std::string dir = p.is_input ? "input" : "output";
    ofs << "| " << p.name << " | " << dir << " | " << p.width << " | " << desc
        << " |\n";
  }
  ofs << "\n";
}

void GenDoc::emit_internal_signals(std::ofstream &ofs,
                                   const std::vector<RegisterView> &registers,
                                   int comb_count, int instance_count) {
  ofs << "### Internal Signals\n\n";
  ofs << "- Registers: " << registers.size() << "\n";
  ofs << "- Combinational ops: " << comb_count << "\n";
  ofs << "- Instances: " << instance_count << "\n\n";
}

void GenDoc::emit_register_summary(std::ofstream &ofs,
                                   const std::vector<RegisterView> &registers) {
  ofs << "### Register Summary\n\n";
  ofs << "| Register | Width |\n";
  ofs << "|----------|-------|\n";
  for (const auto &r : registers) {
    ofs << "| " << r.name << " | " << r.width << " |\n";
  }
  ofs << "\n";
}

void GenDoc::emit_programmers_guide(
    std::ofstream &ofs, bool has_clock, bool has_reset,
    const std::string &name, const std::vector<PortView> &ports,
    const std::vector<PortView> &input_ports,
    const std::vector<PortView> &output_ports, bool has_registers) {
  ofs << "## Programmer's Guide\n\n";
  emit_quick_start(ofs, input_ports, output_ports);
  if (has_clock && has_reset)
    emit_reset_sequence(ofs, ports);
  emit_cpp_model_usage(ofs, has_clock, name, input_ports, output_ports,
                       has_registers);
}

void GenDoc::emit_quick_start(
    std::ofstream &ofs, const std::vector<PortView> &input_ports,
    const std::vector<PortView> &output_ports) {
  ofs << "### Quick Start\n\n";
  ofs << "This module has " << input_ports.size() << " input port(s) and "
      << output_ports.size() << " output port(s).\n\n";
}

void GenDoc::emit_reset_sequence(std::ofstream &ofs,
                                 const std::vector<PortView> &ports) {
  std::string reset_name;
  for (const auto &p : ports) {
    if (hirct::is_reset_port(p.name)) {
      reset_name = p.name;
      break;
    }
  }

  bool active_low = hirct::is_active_low_reset(reset_name);
  int assert_val = active_low ? 0 : 1;
  int deassert_val = active_low ? 1 : 0;

  ofs << "### Reset Sequence\n\n";
  ofs << "1. Assert `" << reset_name << "` to " << assert_val << "\n";
  ofs << "2. Wait 1 clock cycle\n";
  ofs << "3. Deassert `" << reset_name << "` to " << deassert_val << "\n\n";
}

void GenDoc::emit_cpp_model_usage(
    std::ofstream &ofs, bool has_clock, const std::string &name,
    const std::vector<PortView> &input_ports,
    const std::vector<PortView> &output_ports, bool has_registers) {
  std::string first_input;
  for (const auto &p : input_ports) {
    if (!hirct::is_clock_port(p.name) && !hirct::is_reset_port(p.name)) {
      first_input = p.name;
      break;
    }
  }

  std::string first_output;
  if (!output_ports.empty())
    first_output = output_ports[0].name;

  bool is_combinational = !has_registers && !has_clock;
  std::string step_fn = is_combinational ? "eval_comb" : "step";

  ofs << "### C++ Model Usage\n\n";
  ofs << "```cpp\n";
  ofs << "#include \"" << name << ".h\"\n";
  ofs << name << " model;\n";
  if (!is_combinational)
    ofs << "model.do_reset();\n";
  if (!first_input.empty())
    ofs << "model." << first_input << " = 0x1234;\n";
  ofs << "model." << step_fn << "();\n";
  if (!first_output.empty())
    ofs << "printf(\"output: 0x%x\\n\", model." << first_output << ");\n";
  ofs << "```\n\n";
}

void GenDoc::emit_module_hierarchy(
    std::ofstream &ofs, const std::string &name,
    const std::vector<std::pair<std::string, std::string>> &instances) {
  ofs << "## Module Hierarchy\n\n";
  ofs << "- " << name << "\n";
  for (const auto &[inst_name, mod_type] : instances) {
    ofs << "  - " << inst_name << ": " << mod_type << "\n";
  }
  ofs << "\n";
}

} // namespace hirct
